import{c as a,Q as t,j as r,m as l}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Build crates","description":"","frontmatter":{},"headers":[],"relativePath":"workflows/build-crates.md","filePath":"workflows/build-crates.md","lastUpdated":null}'),i={name:"workflows/build-crates.md"};function o(s,e,d,n,c,p){return t(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="build-crates" tabindex="-1">Build crates <a class="header-anchor" href="#build-crates" aria-label="Permalink to &quot;Build crates&quot;">​</a></h1><p>Audience: DJs and music collectors<br> Goal: make review lists without pretending the algorithm has final taste<br> Type: how-to</p><p>A crate is a working list. It can be a warmup pool, a peak-time pool, a left-field folder, or a short list to audition later.</p><h2 id="recommended-loop" tabindex="-1">Recommended loop <a class="header-anchor" href="#recommended-loop" aria-label="Permalink to &quot;Recommended loop&quot;">​</a></h2><ol><li>Start with a narrow seed: a track, prompt, classifier, or filter.</li><li>Search with the mode that matches the seed.</li><li>Add candidates to the current set or export list.</li><li>Remove tracks that do not pass a listening check.</li><li>Repeat with a different seed or signal.</li></ol><h2 id="keep-crates-small" tabindex="-1">Keep crates small <a class="header-anchor" href="#keep-crates-small" aria-label="Permalink to &quot;Keep crates small&quot;">​</a></h2><p>The most useful crates are reviewed crates. Large unreviewed exports usually become another library to sort later.</p><p>Use <code>Track limit</code>, result limits, and focused prompts to keep the output small enough to inspect.</p><h2 id="mix-signals-deliberately" tabindex="-1">Mix signals deliberately <a class="header-anchor" href="#mix-signals-deliberately" aria-label="Permalink to &quot;Mix signals deliberately&quot;">​</a></h2><p>Good crate work often combines signals:</p><ul><li>MERT for near audio neighbors;</li><li>SONARA for feature balance;</li><li>CLAP for descriptive searches;</li><li>CLASS for your own trained concepts;</li><li>SET for ordered previews.</li></ul><p>Do not treat MAEST genre labels as a crate builder unless your workflow is specifically about writing or inspecting genre metadata.</p>',12)])])}const m=a(i,[["render",o]]);export{h as __pageData,m as default};
